+{
+  "packet_id": "FP-P2D-049",
+  "case_id": "dataframe_isnull_alias_mixed_strict",
+  "mode": "strict",
+  "operation": "dataframe_isnull",
+  "frame": {
+    "index": [
+      { "kind": "utf8", "value": "r1" },
+      { "kind": "utf8", "value": "r2" },
+      { "kind": "utf8", "value": "r3" }
+    ],
+    "columns": {
+      "x": [
+        { "kind": "int64", "value": 1 },
+        { "kind": "null", "value": "null" },
+        { "kind": "int64", "value": 2 }
+      ],
+      "y": [
+        { "kind": "utf8", "value": "a" },
+        { "kind": "utf8", "value": "b" },
+        { "kind": "null", "value": "na_t" }
+      ]
+    }
+  },
+  "expected_frame": {
+    "index": [
+      { "kind": "utf8", "value": "r1" },
+      { "kind": "utf8", "value": "r2" },
+      { "kind": "utf8", "value": "r3" }
+    ],
+    "columns": {
+      "x": [
+        { "kind": "bool", "value": false },
+        { "kind": "bool", "value": true },
+        { "kind": "bool", "value": false }
+      ],
+      "y": [
+        { "kind": "bool", "value": false },
+        { "kind": "bool", "value": false },
+        { "kind": "bool", "value": true }
+      ]
+    }
+  }
+}

